# Deobfuscated Code

After decoding the string table (base64 with character mapping) and resolving all references, here's the clean version:

```javascript
// Constants
var TAU = 6.283;          // ≈ 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // ≈ √(1/2)

// Simulation parameters
var params = {
  attractionRange: 4000,   // 0xFA0
  springCoeff: 0.004,      // spring coefficient
  amplification: 0.92,     // damping/velocity retention factor
  gravityPull: 0.0003,     // center gravity
  streamCount: 40,         // max particles
  streamDecay: 0.04,       // particle drag
  theta: 0.06              // camera smoothing
};

// --- NODES ---
var hub = { id: 'hub', label: 'Hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 };
var alpha = { id: 'alpha', label: 'Alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 };
var beta = { id: 'beta', label: 'Beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 };
var gamma = { id: 'gamma', label: 'Gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 };
var delta = { id: 'delta', label: 'Delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 };
var epsilon = { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 };

var nodes = [hub, alpha, beta, gamma, delta, epsilon];

// --- EDGES (springs) ---
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// --- CAMERA ---
var camera = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// --- PARTICLES ---
var particles = [];
var tick = 0;

// Find node by id
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// Physics step
function updatePhysics() {
  // 1) Coulomb-like repulsion between all node pairs
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = params.attractionRange / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Spring forces along edges
  for (var e = 0; e < edges.length; e++) {
    var nA = findNode(edges[e].a);
    var nB = findNode(edges[e].b);
    if (!nA || !nB) continue;
    var dx = nB.x - nA.x;
    var dy = nB.y - nA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || params.springCoeff) * displacement;
    nA.vx += (dx / dist) * force;
    nA.vy += (dy / dist) * force;
    nB.vx -= (dx / dist) * force;
    nB.vy -= (dy / dist) * force;
  }

  // 3) Center gravity + damping + integration
  for (var n = 0; n < nodes.length; n++) {
    nodes[n].vx += (400 - nodes[n].x) * params.gravityPull;
    nodes[n].vy += (300 - nodes[n].y) * params.gravityPull;
    nodes[n].vx *= params.amplification;  // damping
    nodes[n].vy *= params.amplification;
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// Spawn a particle from a random node
function spawnParticle() {
  if (particles.length >= params.streamCount) return;
  var node = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: node.x,
    y: node.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// Update particles
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    p.age++;
    if (p.age > p.maxAge) { particles.splice(i, 1); continue; }
    p.vx *= (1 - params.streamDecay * 0.125);
    p.vy *= (1 - params.streamDecay * 0.125);
    p.x += p.vx;
    p.y += p.vy;
  }
}

// Smooth camera
function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * params.theta;
  camera.y += (cameraTarget.y - camera.y) * params.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * params.theta;
}

// Main loop
function step() {
  updatePhysics();
  updateParticles();
  updateCamera();
  if (tick % 3 === 0) spawnParticle();
  tick++;
}

setInterval(step, 16); // ~60fps
```

## Summary

This is a **force-directed graph layout simulation** with:

| Component | Algorithm |
|---|---|
| **Repulsion** | Coulomb's law (inverse-square) between all node pairs |
| **Attraction** | Hooke's law (spring forces) along edges |
| **Centering** | Weak gravity pulling nodes toward (400, 300) |
| **Damping** | Velocity multiplied by 0.92 each tick |
| **Particles** | Cosmetic particles spawned from random nodes, decaying over time |
| **Camera** | Exponential smoothing (lerp) toward target at rate 0.06 |

The graph has **6 nodes** (Hub, Alpha, Beta, Gamma, Delta, Epsilon) connected by **8 spring edges** in a hub-and-spoke topology with some cross-links.
